 15→const CREDIT_COST = 3;
 16→
 17→const LlmsTxtGenerator: React.FC<Props> = ({ onBack, user, onDeductCredits }) => {
 18→  // Form state
 19→  const [siteName, setSiteName] = useState('');
 20→  const [siteUrl, setSiteUrl] = useState('');
 21→  const [description, setDescription] = useState('');
 22→  const [entity, setEntity] = useState('Organization');
 23→  const [contactEmail, setContactEmail] = useState('');
 24→  const [contactPhone, setContactPhone] = useState('');
 25→  const [contactAddress, setContactAddress] = useState('');
 26→  const [targetAudience, setTargetAudience] = useState('');
 27→  const [services, setServices] = useState<Array<{ name: string; description: string; url: string }>>([
 28→    { name: '', description: '', url: '' },
 29→  ]);
 30→  const [keyPages, setKeyPages] = useState<Array<{ title: string; url: string; description: string }>>([
 31→    { title: '', url: '', description: '' },
 32→  ]);
 33→  const [socialLinks, setSocialLinks] = useState('');
 34→
 35→  // Result state
 36→  const [isGenerating, setIsGenerating] = useState(false);
 37→  const [result, setResult] = useState<{ content: string; sections: number; wordCount: number } | null>(null);
 38→  const [copied, setCopied] = useState(false);
 39→
 40→  const isValid = siteName && siteUrl && description && contactEmail;
 41→
 42→  const handleGenerate = async () => {
 43→    if (!isValid) return;
 44→    const canProceed = onDeductCredits(CREDIT_COST);
 45→    if (!canProceed) return;
 46→
 47→    setIsGenerating(true);
 48→    try {
 49→      const output = await generateLlmsTxt({
 50→        siteName,
 51→        siteUrl: siteUrl.replace(/\/$/, ''),
 52→        description,
 53→        entity,
 54→        services: services.filter(s => s.name),
 55→        keyPages: keyPages.filter(p => p.title && p.url),
 56→        contact: {
 57→          email: contactEmail,
 58→          ...(contactPhone ? { phone: contactPhone } : {}),
 59→          ...(contactAddress ? { address: contactAddress } : {}),
 60→        },
 61→        socialLinks: socialLinks.split('\n').map(s => s.trim()).filter(Boolean),
 62→        targetAudience: targetAudience || undefined,
 63→      });
 64→      setResult(output);
 65→    } catch (err) {
 66→      console.error('Generation failed:', err);
 67→    } finally {
 68→      setIsGenerating(false);
 69→    }
 70→  };
 71→
 72→  const handleCopy = () => {
 73→    if (!result) return;
 74→    navigator.clipboard.writeText(result.content);
 75→    setCopied(true);
 76→    setTimeout(() => setCopied(false), 2000);
 77→  };
 78→
 79→  const handleDownload = () => {
 80→    if (!result) return;
 81→    const blob = new Blob([result.content], { type: 'text/plain' });
 82→    const url = URL.createObjectURL(blob);
 83→    const a = document.createElement('a');
 84→    a.href = url;
 85→    a.download = 'llms.txt';
 86→    a.click();
 87→    URL.revokeObjectURL(url);
 88→  };
 89→
 90→  return (
 91→    <div className="w-full px-6 py-8 animate-in fade-in duration-500">
 92→      {/* Header */}
 93→      <div className="flex items-center gap-4 mb-8">
 94→        <button onClick={onBack} className="p-2 rounded-xl hover:bg-white/[0.04] transition-colors">
 95→          <ArrowLeft size={20} className="text-gray-400" />
 96→        </button>
 97→        <div className="flex-1">
 98→          <div className="flex items-center gap-3">
 99→            <h1 className="text-2xl font-bold text-white">Générateur <span className="gradient-text">llms.txt</span></h1>
