      },
    }, null, 2),
    gasCost: 0,
  },
];

// ── Usage Data (mock) ──

export const getUsageData = (): ApiUsageDay[] => {
  const days: ApiUsageDay[] = [];
  const now = new Date();
  for (let i = 29; i >= 0; i--) {
    const d = new Date(now);
    d.setDate(d.getDate() - i);
    const seed = d.getDate() + d.getMonth() * 31;
    const success = 20 + Math.round(((seed * 7 + i * 13) % 161));
    const errors = Math.round(((seed * 3 + i * 5) % 13));
    days.push({
      date: d.toISOString().split('T')[0],
      success,
      errors,
    });
  }
  return days;
};

export const getUsageStats = (): ApiUsageStats => {
  const data = getUsageData();
  const totalSuccess = data.reduce((s, d) => s + d.success, 0);
  const totalErrors = data.reduce((s, d) => s + d.errors, 0);
  const total = totalSuccess + totalErrors;
  return {
    requestsPerDay: Math.round(total / data.length),
    errorRate: total > 0 ? Math.round((totalErrors / total) * 10000) / 100 : 0,
    avgLatency: 120 + Math.round(((data.length * 7) % 80)),
  };
};

