                        <h4 className="text-xs font-semibold text-gray-500 uppercase">Exemple de reponse</h4>
                        <button
                          onClick={() => copyToClipboard(ep.exampleResponse, `resp_${ep.path}`)}
                          className="flex items-center gap-1 text-xs text-gray-500 hover:text-gray-300 transition-colors"
                        >
                          {copiedId === `resp_${ep.path}` ? <Check size={12} className="text-emerald-400" /> : <Copy size={12} />}
                          {copiedId === `resp_${ep.path}` ? 'Copie !' : 'Copier'}
                        </button>
                      </div>
                      <pre className="bg-black/50 border border-white/[0.06] rounded-lg p-4 text-xs font-mono text-gray-300 overflow-x-auto max-h-64 custom-scrollbar">
                        {ep.exampleResponse}
                      </pre>
                    </div>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </div>

      {/* Code examples */}
      <div>
        <h3 className="text-sm font-semibold text-gray-400 uppercase tracking-wider mb-3">Exemples de code</h3>
        <div className="ninja-card overflow-hidden">
          <div className="flex border-b border-white/[0.06]">
            {(['curl', 'javascript', 'python'] as const).map((tab) => (
              <button
                key={tab}
                onClick={() => setCodeTab(tab)}
                className={`px-4 py-2.5 text-sm font-medium transition-colors ${
                  codeTab === tab
                    ? 'text-purple-400 border-b-2 border-purple-500 bg-white/[0.02]'
                    : 'text-gray-500 hover:text-gray-300'
                }`}
              >
                {tab === 'curl' ? 'cURL' : tab === 'javascript' ? 'JavaScript' : 'Python'}
              </button>
            ))}
          </div>
          <div className="relative p-4">
            <button
              onClick={() => copyToClipboard(codeExamples[codeTab], `code_${codeTab}`)}
              className="absolute top-3 right-3 flex items-center gap-1 text-xs text-gray-500 hover:text-gray-300 transition-colors bg-black/40 px-2 py-1 rounded"
            >
              {copiedId === `code_${codeTab}` ? <Check size={12} className="text-emerald-400" /> : <Copy size={12} />}
              {copiedId === `code_${codeTab}` ? 'Copie !' : 'Copier'}
            </button>
            <pre className="text-xs font-mono text-gray-300 overflow-x-auto custom-scrollbar whitespace-pre-wrap">
              {codeExamples[codeTab]}
            </pre>
          </div>
        </div>
      </div>
    </div>
  );

  // ── Tab: API Keys ──

  const renderKeys = () => (
    <div className="space-y-6 animate-in fade-in duration-300">
      {/* Create key form */}
      <div className="ninja-card p-5">
        <h3 className="text-sm font-semibold text-white mb-3 flex items-center gap-2">
          <Plus size={16} className="text-purple-400" /> Nouvelle cle
        </h3>
        <div className="flex gap-3">
          <input
            type="text"
            value={newKeyName}
            onChange={(e) => setNewKeyName(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleCreateKey()}
            placeholder="Nom de la cle (ex: Production, Staging...)"
            className="flex-1 bg-[#111111] border border-white/[0.08] rounded-lg px-4 py-2.5 text-sm text-gray-200 placeholder-gray-600 focus:outline-none focus:border-purple-500/40 transition-colors"
          />
          <button
            onClick={handleCreateKey}
            disabled={!newKeyName.trim()}
            className="btn-gradient px-5 py-2.5 text-sm text-white disabled:opacity-40 disabled:cursor-not-allowed"
          >
            Creer
          </button>
        </div>
      </div>

      {/* Keys list */}
      {keys.length === 0 ? (
        <div className="ninja-card p-10 text-center">
          <Key size={32} className="text-gray-600 mx-auto mb-3" />
          <p className="text-gray-500 text-sm">Aucune cle API. Creez-en une pour commencer.</p>
        </div>
      ) : (
        <div className="space-y-3">
          {keys.map((k) => (
            <div key={k.id} className="ninja-card p-4 flex flex-col sm:flex-row sm:items-center gap-3">
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2 mb-1">
                  <span className="text-sm font-semibold text-white">{k.name}</span>
                  <span
                    className={`text-[10px] font-bold px-2 py-0.5 rounded-full ${
                      k.status === 'active'
                        ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20'
                        : 'bg-red-500/10 text-red-400 border border-red-500/20'
                    }`}
                  >
                    {k.status === 'active' ? 'Actif' : 'Revoque'}
                  </span>
                </div>
                <div className="flex items-center gap-2">
                  <code className="text-xs font-mono text-gray-500">
                    {k.key.slice(0, 12)}...
                  </code>
                  <button
                    onClick={() => copyToClipboard(k.key, `key_${k.id}`)}
                    className="text-gray-500 hover:text-gray-300 transition-colors"
                    title="Copier la cle complete"
                  >
                    {copiedId === `key_${k.id}` ? (
                      <Check size={12} className="text-emerald-400" />
                    ) : (
                      <Copy size={12} />
                    )}
                  </button>
                </div>
                <p className="text-[11px] text-gray-600 mt-1">
                  Cree le {new Date(k.createdAt).toLocaleDateString('fr-FR')}
                </p>
              </div>
              <div className="flex items-center gap-2">
                {k.status === 'active' && (
                  <>
                    <button
                      onClick={() => handleRegenerateKey(k.id)}
                      className="flex items-center gap-1.5 text-xs text-gray-400 hover:text-gray-200 bg-white/[0.04] hover:bg-white/[0.08] px-3 py-1.5 rounded-lg transition-colors"
                      title="Regenerer"
                    >
                      <RefreshCw size={12} /> Regenerer
                    </button>
                    <button
                      onClick={() => handleRevokeKey(k.id)}
                      className="flex items-center gap-1.5 text-xs text-red-400 hover:text-red-300 bg-red-500/5 hover:bg-red-500/10 px-3 py-1.5 rounded-lg transition-colors"
                      title="Revoquer"
                    >
                      <Shield size={12} /> Revoquer
                    </button>
                  </>
                )}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );

  // ── Tab: Webhooks ──

  const renderWebhooks = () => (
    <div className="space-y-6 animate-in fade-in duration-300">
      {/* Create webhook form */}
      <div className="ninja-card p-5">
        <h3 className="text-sm font-semibold text-white mb-3 flex items-center gap-2">
          <Plus size={16} className="text-purple-400" /> Ajouter un webhook
        </h3>
        <div className="space-y-3">
          <input
            type="url"
            value={webhookUrl}
            onChange={(e) => setWebhookUrl(e.target.value)}
            placeholder="https://your-server.com/webhook"
            className="w-full bg-[#111111] border border-white/[0.08] rounded-lg px-4 py-2.5 text-sm text-gray-200 placeholder-gray-600 focus:outline-none focus:border-purple-500/40 transition-colors"
          />
          <div>
            <p className="text-xs text-gray-500 mb-2">Evenements</p>
            <div className="flex flex-wrap gap-2">
              {WEBHOOK_EVENTS.map((ev) => {
                const selected = webhookEvents.includes(ev.value);
                return (
                  <button
                    key={ev.value}
                    onClick={() => toggleWebhookEvent(ev.value)}
                    className={`text-xs px-3 py-1.5 rounded-lg border transition-colors ${
                      selected
                        ? 'bg-purple-500/10 text-purple-400 border-purple-500/30'
                        : 'bg-white/[0.02] text-gray-500 border-white/[0.08] hover:border-white/[0.15]'
                    }`}
                  >
                    {ev.label}
                  </button>
                );
              })}
            </div>
          </div>
          <button
            onClick={handleCreateWebhook}
            disabled={!webhookUrl.trim() || webhookEvents.length === 0}
            className="btn-gradient px-5 py-2.5 text-sm text-white disabled:opacity-40 disabled:cursor-not-allowed"
          >
            Ajouter
          </button>
        </div>
      </div>

      {/* Webhooks list */}
      {webhooks.length === 0 ? (
        <div className="ninja-card p-10 text-center">
          <Globe size={32} className="text-gray-600 mx-auto mb-3" />
          <p className="text-gray-500 text-sm">Aucun webhook configure.</p>
        </div>
      ) : (
        <div className="space-y-3">
          {webhooks.map((wh) => (
            <div key={wh.id} className="ninja-card p-4">
              <div className="flex flex-col sm:flex-row sm:items-center gap-3">
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 mb-2">
                    <code className="text-sm font-mono text-gray-300 truncate max-w-[300px]" title={wh.url}>
                      {wh.url.length > 45 ? wh.url.slice(0, 45) + '...' : wh.url}
                    </code>
                  </div>
                  <div className="flex flex-wrap gap-1.5 mb-2">
                    {wh.events.map((ev) => (
                      <span
                        key={ev}
                        className={`text-[10px] font-medium px-2 py-0.5 rounded-full border ${EVENT_COLORS[ev]}`}
                      >
                        {ev}
                      </span>
                    ))}
                  </div>
                  <p className="text-[11px] text-gray-600">
                    {wh.lastDelivery
                      ? `Derniere livraison : ${new Date(wh.lastDelivery).toLocaleString('fr-FR')}`
                      : 'Aucune livraison'}
                    {' '}· Cree le {new Date(wh.createdAt).toLocaleDateString('fr-FR')}
                  </p>
                </div>
                <div className="flex items-center gap-3">
                  <button
                    onClick={() => handleToggleWebhook(wh.id)}
                    className="text-gray-400 hover:text-gray-200 transition-colors"
                    title={wh.active ? 'Desactiver' : 'Activer'}
                  >
                    {wh.active ? (
                      <ToggleRight size={24} className="text-emerald-400" />
                    ) : (
                      <ToggleLeft size={24} className="text-gray-600" />
                    )}
                  </button>
                  <button
                    onClick={() => handleDeleteWebhook(wh.id)}
                    className="text-gray-500 hover:text-red-400 transition-colors"
                    title="Supprimer"
                  >
                    <Trash2 size={16} />
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );

  // ── Tab: Usage ──

  const renderUsage = () => (
    <div className="space-y-6 animate-in fade-in duration-300">
      {/* KPI cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="ninja-card p-5">
          <div className="flex items-center gap-2 mb-2">
            <Activity size={16} className="text-purple-400" />
            <span className="text-xs text-gray-500 uppercase tracking-wider">Requetes/jour</span>
          </div>
          <p className="text-2xl font-bold text-white">{stats.requestsPerDay}</p>
          <p className="text-xs text-gray-600 mt-1">Moyenne sur 30 jours</p>
        </div>
        <div className="ninja-card p-5">
          <div className="flex items-center gap-2 mb-2">
            <AlertTriangle size={16} className="text-amber-400" />
            <span className="text-xs text-gray-500 uppercase tracking-wider">Taux d'erreur</span>
          </div>
          <p className="text-2xl font-bold text-white">{stats.errorRate}%</p>
          <p className="text-xs text-gray-600 mt-1">Erreurs / total requetes</p>
        </div>
        <div className="ninja-card p-5">
          <div className="flex items-center gap-2 mb-2">
            <Clock size={16} className="text-blue-400" />
            <span className="text-xs text-gray-500 uppercase tracking-wider">Latence moyenne</span>
          </div>
          <p className="text-2xl font-bold text-white">{stats.avgLatency} ms</p>
          <p className="text-xs text-gray-600 mt-1">Temps de reponse moyen</p>
        </div>
      </div>

      {/* Chart */}
      <div className="ninja-card p-5">
        <h3 className="text-sm font-semibold text-white mb-4">Requetes API - 30 derniers jours</h3>
        <div className="h-72">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={usageData} barGap={0}>
              <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.04)" />
              <XAxis
                dataKey="date"
                tick={{ fill: '#6b7280', fontSize: 10 }}
                tickFormatter={(v: string) => v.slice(5)}
                axisLine={{ stroke: 'rgba(255,255,255,0.06)' }}
              />
              <YAxis
                tick={{ fill: '#6b7280', fontSize: 10 }}
                axisLine={{ stroke: 'rgba(255,255,255,0.06)' }}
              />
              <Tooltip
                contentStyle={{
                  background: '#1a1a1a',
                  border: '1px solid rgba(255,255,255,0.08)',
                  borderRadius: '8px',
                  fontSize: '12px',
                }}
                labelStyle={{ color: '#9ca3af' }}
              />
              <Legend
                wrapperStyle={{ fontSize: '12px', color: '#9ca3af' }}
              />
              <Bar dataKey="success" stackId="a" fill="#10b981" name="Succes" radius={[0, 0, 0, 0]} />
              <Bar dataKey="errors" stackId="a" fill="#ef4444" name="Erreurs" radius={[2, 2, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* SDK section */}
      <div>
        <h3 className="text-sm font-semibold text-gray-400 uppercase tracking-wider mb-3">SDK officiels</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="ninja-card p-5">
            <div className="flex items-center gap-2 mb-3">
              <Code2 size={16} className="text-amber-400" />
              <span className="text-sm font-semibold text-white">Node.js / JavaScript</span>
            </div>
            <div className="relative">
              <pre className="bg-black/50 border border-white/[0.06] rounded-lg p-3 text-xs font-mono text-gray-300">
                npm install @citedby/sdk
              </pre>
              <button
                onClick={() => copyToClipboard('npm install @citedby/sdk', 'sdk_npm')}
                className="absolute top-2 right-2 text-gray-500 hover:text-gray-300 transition-colors"
              >
                {copiedId === 'sdk_npm' ? <Check size={12} className="text-emerald-400" /> : <Copy size={12} />}
              </button>
            </div>
          </div>
          <div className="ninja-card p-5">
            <div className="flex items-center gap-2 mb-3">
              <Terminal size={16} className="text-blue-400" />
              <span className="text-sm font-semibold text-white">Python</span>
            </div>
            <div className="relative">
              <pre className="bg-black/50 border border-white/[0.06] rounded-lg p-3 text-xs font-mono text-gray-300">
                pip install citedby
              </pre>
              <button
                onClick={() => copyToClipboard('pip install citedby', 'sdk_pip')}
                className="absolute top-2 right-2 text-gray-500 hover:text-gray-300 transition-colors"
              >
                {copiedId === 'sdk_pip' ? <Check size={12} className="text-emerald-400" /> : <Copy size={12} />}
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );

  // ── Main render ──

  return (
    <div className="w-full px-6 py-8 animate-in fade-in duration-500">
      {/* Header */}
      <div className="flex items-center gap-4 mb-8">
        <button onClick={onBack} className="p-2 rounded-xl hover:bg-white/[0.04] transition-colors">
          <ArrowLeft size={20} className="text-gray-400" />
        </button>
        <div className="flex-1">
          <div className="flex items-center gap-3">
            <h1 className="text-2xl font-bold text-white">
              <span className="gradient-text">API</span> Developer Hub
            </h1>
            <span className="bg-purple-500/10 text-purple-400 text-[10px] font-bold px-2.5 py-1 rounded-full border border-purple-500/20">
              BETA
            </span>
          </div>
          <p className="text-sm text-gray-500 mt-1">
            Integrez CitedBy.ai dans vos applications via notre API REST.
          </p>
        </div>
      </div>

      {/* Tab bar */}
      <div className="flex gap-1 mb-6 border-b border-white/[0.06] overflow-x-auto">
        {TABS.map((tab) => {
          const Icon = tab.icon;
          const isActive = activeTab === tab.id;
          return (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`flex items-center gap-2 px-4 py-3 text-sm font-medium whitespace-nowrap transition-colors border-b-2 ${
                isActive
                  ? 'text-purple-400 border-purple-500'
                  : 'text-gray-500 border-transparent hover:text-gray-300 hover:border-white/[0.1]'
              }`}
            >
              <Icon size={16} />
              {tab.label}
            </button>
          );
        })}
      </div>

      {/* Tab content */}
      {activeTab === 'docs' && renderDocs()}
      {activeTab === 'keys' && renderKeys()}
      {activeTab === 'webhooks' && renderWebhooks()}
      {activeTab === 'usage' && renderUsage()}
    </div>
  );
};

export default ApiDeveloper;
